const payload = $input.first().json.body || $input.first().json;
const creds = payload.user_credentials?.google_calendar || {};

return [{
  json: {
    api_key: creds.api_key || '',
    calendar_id: creds.calendar_id || 'primary',
    date: payload.date,
    duration_minutes: payload.duration_minutes || 60
  }
}];

const events = $input.first().json.items || [];
const duration = $('Extract Credentials').first().json.duration_minutes;

// Find free slots
const busySlots = events.map(e => ({
  start: new Date(e.start.dateTime || e.start.date),
  end: new Date(e.end.dateTime || e.end.date)
}));

const freeSlots = [];
const dayStart = new Date($('Extract Credentials').first().json.date + 'T09:00:00');
const dayEnd = new Date($('Extract Credentials').first().json.date + 'T18:00:00');

let current = new Date(dayStart);
for (const busy of busySlots) {
  if (busy.start > current) {
    freeSlots.push({ start: new Date(current), end: new Date(busy.start) });
  }
  current = new Date(Math.max(current.getTime(), busy.end.getTime()));
}
if (current < dayEnd) {
  freeSlots.push({ start: new Date(current), end: new Date(dayEnd) });
}

const available = freeSlots.filter(slot => {
  const mins = (slot.end - slot.start) / 60000;
  return mins >= duration;
}).map(slot => ({
  start: slot.start.toISOString(),
  end: slot.end.toISOString(),
  duration_minutes: Math.round((slot.end - slot.start) / 60000)
}));

return [{ json: { date: $('Extract Credentials').first().json.date, available_slots: available, total_events: events.length } }];
